// Video Raster -- line-by-line reveal + packetization + chroma separation.
uniform vec4 uRaster;   // x=scanRate, y=lineCount, z=afterglow, w=time(=absTime*scanRate)
uniform vec4 uPacket;   // x=packetize, y=packetSize, z=driftSpeed, w=chromaSplit
uniform vec4 uLook;     // x=detail, y=ptpRate, z=palette, w=absTime
out vec4 fragColor;
const float PI = 3.14159265;

float hash21(vec2 p){ return fract(sin(dot(p, vec2(127.1,311.7)))*43758.5453); }

// cyclic signal palette: cyan -> green -> magenta-ish, hue rotated by uLook.z
vec3 sigPalette(float v, float hue){
    vec3 a = vec3(0.45, 0.55, 0.6);
    vec3 b = vec3(0.45, 0.55, 0.6);
    vec3 c = vec3(1.0, 1.0, 0.6);
    vec3 d = vec3(0.55, 0.35, 0.15) + hue;
    return a + b*cos(6.28318*(c*v + d));
}

// the procedural 'image': fine moving cells in the signal palette
vec3 sourceImage(vec2 uv, float detail, float hue, float t){
    vec2 g = uv * mix(20.0, 90.0, detail*0.5);
    float cell = hash21(floor(g) + floor(t*0.6));
    float fine = 0.5 + 0.5*sin(uv.x*60.0*detail + t) * sin(uv.y*34.0*detail - t*0.7);
    float v = mix(cell, fine, 0.5);
    return sigPalette(v, hue) * (0.35 + 0.5*v);
}

void main(){
    vec2 uv = vUV.st;
    float t = uLook.w;

    float lines  = clamp(uRaster.y, 90.0, 720.0);
    float row    = floor((1.0 - uv.y) * lines) / lines;   // 0 at top, increasing downward
    float scan   = fract(uRaster.w);                       // active scan position (0..1 top->bottom)
    float hue    = uLook.z;
    float detail = uLook.x;

    vec3 img = sourceImage(uv, detail, hue, t);

    // --- raster reveal: only rows above/at the sweep are 'drawn' ---
    float drawn = step(row, scan);
    // phosphor afterglow just below the active line
    float below = row - scan;
    float afterglow = exp(-max(below,0.0) * mix(40.0, 6.0, uRaster.z)) * step(scan, row);

    vec3 col = img * drawn;
    col += vec3(0.10, 0.55, 0.7) * afterglow * 0.6;        // cyan-green phosphor trail

    // white-hot active scanline
    float lineGlow = smoothstep(2.0/lines, 0.0, abs(row - scan));
    col += vec3(1.0) * lineGlow * 1.2;

    // --- RGB chroma separation at the active boundary, re-registers away from it ---
    float boundary = exp(-abs(row - scan) * 30.0);
    float sp = uPacket.w * 0.004 * boundary;
    // approximate by sampling the source image shifted (cheap, no input texture)
    vec3 chroma;
    chroma.r = sourceImage(uv + vec2(sp,0.0), detail, hue, t).r * drawn;
    chroma.g = img.g * drawn;
    chroma.b = sourceImage(uv - vec2(sp,0.0), detail, hue, t).b * drawn;
    col = mix(col, chroma + vec3(1.0)*lineGlow*1.2 + vec3(0.10,0.55,0.7)*afterglow*0.6, boundary);

    // --- packetization on the PTP beat: quantize the left half of each drawn row ---
    float beat   = fract(uLook.w * uLook.y);
    float pktAmt = uPacket.x * smoothstep(0.0, 0.3, beat) * (1.0 - smoothstep(0.6, 1.0, beat));
    float psize  = uPacket.y;                              // packet block width in uv
    float drift  = t * uPacket.z;
    float x = uv.x + drift;
    float cellId = floor(x / psize);
    float inCell = fract(x / psize);
    float gap = smoothstep(0.82, 0.86, inCell);            // gap between packets -> discrete blocks
    float pktBright = 0.6 + 0.4*hash21(vec2(cellId, row*lines));
    // only on the left portion (mid-transmission); right side stays a clean reassembled line
    float region = smoothstep(0.55, 0.45, uv.x);
    vec3 packed = col * (1.0 - gap) * pktBright;
    col = mix(col, packed, pktAmt * region * drawn);

    // near-black ground for undrawn rows
    col += vec3(0.010, 0.012, 0.016) * (1.0 - drawn);

    fragColor = vec4(max(col, 0.0), 1.0);
}

// Bloom + CRT scanline overlay + grain.
uniform vec4 uBloom;   // x=strength, y=threshold, z=scanlines, w=lineCount
out vec4 fragColor;
float hash21(vec2 p){ return fract(sin(dot(p, vec2(127.1,311.7)))*43758.5453); }
void main(){
    vec2 uv = vUV.st;
    vec2 texel = uTDOutputInfo.res.xy;
    vec3 src = texture(sTD2DInputs[0], uv).rgb;
    float thr = uBloom.y;
    vec3 sum = vec3(0.0); float wsum = 0.0;
    const int R = 6;
    for(int x=-R;x<=R;x++){
        for(int y=-R;y<=R;y++){
            vec2 o = vec2(float(x), float(y));
            float w = exp(-dot(o,o)/18.0);
            vec3 s = texture(sTD2DInputs[0], uv + o*texel*2.0).rgb;
            sum += max(s - thr, 0.0) * w;
            wsum += w;
        }
    }
    vec3 col = src + (sum/max(wsum,1e-4)) * uBloom.x;
    // CRT scanline darkening tied to line count
    float lc = clamp(uBloom.w, 90.0, 720.0);
    float scan = 1.0 - uBloom.z * 0.35 * (0.5 + 0.5*sin(uv.y * lc * 6.28318));
    col *= scan;
    col += (hash21(uv*uTDOutputInfo.res.zw)-0.5) * 0.014;
    fragColor = vec4(col, 1.0);
}
